import axios from 'axios';

const handleLogin = async () => {
  try {
    const res = await axios.post('http://localhost:3001/login', {
      username: user,
      password: pass
    });

    if (res.data.success) {
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/home');
    } else {
      alert('Login inválido');
    }

  } catch (err) {
    console.error(err);
  }
};
